-- Bo giai ma chuoi (nhieu thuat toan, chon ngau nhien theo tung hang so luc build)
local function tunzdBleb(a, b)
  local result, bitval = 0, 1
  while a > 0 or b > 0 do
    local abit, bbit = a % 2, b % 2
    if abit ~= bbit then result = result + bitval end
    a = (a - abit) / 2
    b = (b - bbit) / 2
    bitval = bitval * 2
  end
  return result
end
local function uNWodIKuG(bytes, key)
  local out = {}
  for i = 1, #bytes do out[i] = string.char(tunzdBleb(bytes[i], key)) end
  return table.concat(out)
end
local function b6aOUeyIb0eW(bytes, key)
  local out = {}
  for i = 1, #bytes do out[i] = string.char((bytes[i] - key) % 256) end
  return table.concat(out)
end
local function hlmTwrU(bytes, key)
  local n = #bytes
  local out = {}
  for i = 1, n do out[n - i + 1] = string.char(tunzdBleb(bytes[i], key)) end
  return table.concat(out)
end
local function bxRtBo3VVVYQ(descBytes, descKey, descAlg)
  if descAlg == 1 then return uNWodIKuG(descBytes, descKey)
  elseif descAlg == 2 then return b6aOUeyIb0eW(descBytes, descKey)
  else return hlmTwrU(descBytes, descKey) end
end


